class ETG_SalesAgreementVersionCompareUIBuilder extends sysOperationAutomaticUIBuilder
{
    DialogField     dlgConfirmationFirstNumber,dlgConfirmationSecondNumber;
    str             dlgAgreementId;
    Container               conHistory;
    NoYesId         isSalesAgreement;

}

Method.Source:
public void build()
{
    ETG_SalesAgreementVersionCompareContract   contract;

    contract = this.dataContractObject() as ETG_SalesAgreementVersionCompareContract;
    dlgConfirmationFirstNumber = this.addDialogField(methodStr(ETG_SalesAgreementVersionCompareContract, parmConfirmationFirst),contract);
    dlgConfirmationSecondNumber = this.addDialogField(methodStr(ETG_SalesAgreementVersionCompareContract, parmConfirmationSecond),contract);
}

public void getFromDialog()
{
    ETG_SalesAgreementVersionCompareContract contract = this.dataContractObject();
    super();
}

public void postRun()
{
    ETG_SalesAgreementVersionCompareContract contract = this.dataContractObject();
}

public void postBuild() //postRun
{
    ETG_SalesAgreementVersionCompareContract   contract;

    super();

    contract            = this.dataContractObject() as ETG_SalesAgreementVersionCompareContract;
    dlgAgreementId      = contract.parmAgreementId();
    isSalesAgreement    = contract.parmIsSalesAgreement();
    dlgConfirmationFirstNumber = this.bindInfo().getDialogField(contract,methodStr(ETG_SalesAgreementVersionCompareContract, parmConfirmationFirst));

    if(isSalesAgreement == NoYes::Yes)
    {
        dlgConfirmationFirstNumber.registerOverrideMethod(methodStr(FormStringControl, lookup),methodStr(ETG_SalesAgreementVersionCompareUIBuilder, agreementHistoryFirstLookup),
    this);

        if (dlgConfirmationFirstNumber)
        {
            dlgConfirmationFirstNumber.lookupButton(2);
        }

        dlgConfirmationSecondNumber = this.bindInfo().getDialogField(contract,methodStr(ETG_SalesAgreementVersionCompareContract, parmConfirmationSecond));

        dlgConfirmationSecondNumber.registerOverrideMethod(methodStr(FormStringControl, lookup),methodStr(ETG_SalesAgreementVersionCompareUIBuilder, agreementHistorySecondLookup),
    this);

        if (dlgConfirmationSecondNumber)
        {
            dlgConfirmationSecondNumber.lookupButton(2);
        }
    }
    else
    {
        dlgConfirmationFirstNumber.registerOverrideMethod(methodStr(FormStringControl, lookup),methodStr(ETG_SalesAgreementVersionCompareUIBuilder, purchAgreementHistoryFirstLookup),
    this);

        if (dlgConfirmationFirstNumber)
        {
            dlgConfirmationFirstNumber.lookupButton(2);
        }

        dlgConfirmationSecondNumber = this.bindInfo().getDialogField(contract,methodStr(ETG_SalesAgreementVersionCompareContract, parmConfirmationSecond));

        dlgConfirmationSecondNumber.registerOverrideMethod(methodStr(FormStringControl, lookup),methodStr(ETG_SalesAgreementVersionCompareUIBuilder, purchAgreementHistorySecondLookup),
    this);

        if (dlgConfirmationSecondNumber)
        {
            dlgConfirmationSecondNumber.lookupButton(2);
        }
    }
}

private void agreementHistoryFirstLookup(FormStringControl _control)
{
    Query query = new Query();
    QueryBuildDataSource qbds;
    SysTableLookup sysTablelookup;

    //create a table lookup
    sysTablelookup = SysTableLookup::newParameters(tableNum(SalesAgreementHeaderHistory),_control);
    sysTableLookup.addLookupMethod(tableMethodStr(SalesAgreementHeaderHistory, AgreementConfirmation),true);
    sysTableLookup.addLookupfield(fieldnum(SalesAgreementHeaderHistory, SalesNumberSequence));
    sysTableLookup.addLookupfield(fieldnum(SalesAgreementHeaderHistory, ConfirmationNumber));

    //create a query

    query.addDataSource(tableNum(SalesAgreementHeaderHistory)).addRange(
                fieldNum(SalesAgreementHeaderHistory,SalesNumberSequence)).value(queryValue(dlgAgreementId));

    //assign the query and call lookup
    sysTablelookup.parmQuery(query);
    sysTablelookup.performFormLookup();
}

